INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-brew-survival', 'word-brew', 'survival', 'When coffee is freshly made, people call it a fresh brew. It means a cup of coffee that was just prepared.', 'neutral', 'I''ll try the fresh brew.', 'At a cafe, ordering coffee', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-brew-professional', 'word-brew', 'professional', 'In a work setting, "brew" can mean a plan or idea being developed, or it can refer to the office coffee.', 'neutral', 'There''s a new project brewing in the marketing team.', 'At the office, discussing new projects', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-brew-social', 'word-brew', 'social', 'Among friends, "brew" often just means beer or coffee — super casual.', 'informal', 'Let''s grab a brew after the game.', 'Hanging out with friends after a sports game', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-recommend-survival', 'word-recommend', 'survival', 'To recommend means to suggest something you think someone would like. A barista recommends drinks they think you will enjoy.', 'neutral', 'Can you recommend something?', 'At a cafe, asking for a suggestion', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-recommend-professional', 'word-recommend', 'professional', 'In a work context, "recommend" means to formally suggest a course of action or endorse someone.', 'formal', 'I recommend we proceed with the second option.', 'In a meeting, presenting your opinion', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-recommend-ielts', 'word-recommend', 'ielts', 'In academic and formal contexts, "recommend" is used to make suggestions or give advice. It is a key word for expressing opinions in IELTS Speaking.', 'formal', 'I would strongly recommend that visitors explore the historical district.', 'Answering an IELTS Part 2 question about places to visit', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-recommend-toeic', 'word-recommend', 'toeic', 'In business English, "recommend" is used to suggest products, services, or courses of action. Essential for TOEIC opinion questions.', 'formal', 'I would recommend this approach because it has proven effective in similar situations.', 'Expressing an opinion in a TOEIC speaking task', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-recommend-social', 'word-recommend', 'social', 'When chatting with friends, "recommend" is more casual — just telling someone about something good.', 'informal', 'I''d totally recommend that show — it''s so good!', 'Chatting with friends about TV shows', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-seasonal-survival', 'word-seasonal', 'survival', 'Seasonal means available only during a certain time of year. A seasonal special is a drink or food that changes with the seasons.', 'neutral', 'The seasonal blend is really popular right now.', 'At a cafe, hearing about limited-time options', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-seasonal-professional', 'word-seasonal', 'professional', 'In business, "seasonal" refers to patterns that change with the time of year — like seasonal sales or hiring.', 'neutral', 'We see a seasonal dip in sales every January.', 'Reviewing quarterly business data', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-fresh-survival', 'word-fresh', 'survival', 'Fresh means newly made or recently prepared. When a barista says "fresh brew," the coffee was just made.', 'neutral', 'I''d like a fresh brew, please.', 'Ordering at a cafe', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-fresh-professional', 'word-fresh', 'professional', 'At work, "fresh" can mean new ideas, a new perspective, or recent information.', 'neutral', 'Let''s look at this with fresh eyes tomorrow.', 'Discussing a problem at work', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-fresh-social', 'word-fresh', 'social', 'With friends, "fresh" can mean something is cool, new, or exciting — or that someone is being rude ("getting fresh").', 'informal', 'That''s a fresh look! Where''d you get that?', 'Complimenting a friend on their outfit', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-order-survival', 'word-order', 'survival', 'To order means to tell the server what you want. At a cafe, you order the food or drink you would like.', 'neutral', 'I''d like to order a coffee, please.', 'At a cafe, telling the barista what you want', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-order-professional', 'word-order', 'professional', 'In a work setting, "order" can mean to request supplies, or to organize and arrange things.', 'neutral', 'We need to order more supplies for the project.', 'Office supply planning', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-order-social', 'word-order', 'social', 'When hanging out, "order" is casual — just saying what you want at a restaurant.', 'informal', 'I''ll order for us — you want the usual?', 'Deciding what to eat with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-get-survival', 'word-get', 'survival', 'At a cafe, "get" means to order or buy something. It is a casual way to say you want something.', 'informal', 'Can I get a coffee to go?', 'At a cafe, ordering casually', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-get-professional', 'word-get', 'professional', 'At work, "get" often means to understand or to receive information. It can also mean to arrange or organize.', 'neutral', 'I''ll get back to you on that by tomorrow.', 'In a meeting, promising to follow up', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-get-social', 'word-get', 'social', 'With friends, "get" is super versatile — it can mean understand ("I get it"), receive ("got it"), or even empathize ("I got you").', 'informal', 'I got you — no worries!', 'Reassuring a friend', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-wouldlike-survival', 'word-would-like', 'survival', '"Would like" is a polite way to say what you want. It is more formal than "want" but very common in everyday situations.', 'neutral', 'I''d like to try the seasonal special.', 'At a cafe, ordering politely', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-wouldlike-professional', 'word-would-like', 'professional', 'In meetings, "would like" is the polite way to express preferences or requests.', 'formal', 'I would like to suggest an alternative approach.', 'In a meeting, proposing a change', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-appointment-survival', 'word-appointment', 'survival', 'An appointment is a planned meeting, usually with a doctor, dentist, or official office.', 'neutral', 'I need to make an appointment with the doctor.', 'Calling a doctor to schedule a visit', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-appointment-professional', 'word-appointment', 'professional', 'At work, an appointment is a scheduled meeting, often with a client or colleague.', 'formal', 'I have an appointment with the client at 3 PM.', 'Discussing your schedule at work', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-deadline-survival', 'word-deadline', 'survival', 'A deadline is the last moment something must be done by. You encounter deadlines for applications, bills, and appointments.', 'neutral', 'The application deadline is Friday.', 'Reading an important letter', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-deadline-professional', 'word-deadline', 'professional', 'At work, a deadline is the date or time by which a project, task, or deliverable must be completed.', 'formal', 'We need to meet the deadline for the client''s report.', 'Discussing project timelines in a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-deadline-social', 'word-deadline', 'social', 'With friends, "deadline" can be used jokingly or seriously — like the last day to sign up for something fun.', 'informal', 'The sign-up deadline is tonight — don''t miss it!', 'Reminding friends about event registration', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-carry-survival', 'word-carry', 'survival', 'To carry means to hold something and move with it. You carry bags, groceries, or your phone.', 'neutral', 'Can you help me carry these bags?', 'Shopping and needing help with bags', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-carry-professional', 'word-carry', 'professional', 'At work, "carry" often means to take responsibility for something or to include something.', 'neutral', 'This report carries a lot of weight with the board.', 'Discussing the importance of a document', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-carry-social', 'word-carry', 'social', 'In gaming and social contexts, "carry" means to take responsibility for winning when others are struggling.', 'informal', 'Don''t worry, I''ll carry this team!', 'Playing an online game with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stuff-survival', 'word-stuff', 'survival', '"Stuff" is a very common informal word that means "things" — you can use it when you do not know the exact word.', 'informal', 'Where can I put my stuff?', 'Arriving at a new place, looking for a spot for belongings', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stuff-professional', 'word-stuff', 'professional', 'At work, "stuff" is too informal for formal communication. Use "materials," "items," or "matters" instead.', 'informal', 'I need to review the stuff from yesterday''s meeting.', 'Catching up on work (casual office talk)', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stuff-social', 'word-stuff', 'social', 'With friends, "stuff" is perfectly normal — it is the most casual way to refer to things, activities, or situations.', 'informal', 'We did fun stuff all weekend.', 'Telling a friend about your weekend', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-approach-survival', 'word-approach', 'survival', 'To approach means to come closer to something or someone. You approach a counter, a door, or a person.', 'neutral', 'She approached the counter to order.', 'Walking up to a service counter', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-approach-professional', 'word-approach', 'professional', 'At work, "approach" often means a method or way of dealing with something, or to contact someone about a topic.', 'formal', 'We need a different approach to this problem.', 'Brainstorming solutions in a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-approach-ielts', 'word-approach', 'ielts', 'In academic English, "approach" refers to a method of dealing with a topic or problem. It is essential for IELTS Part 3 discussions where you need to analyze different perspectives.', 'formal', 'There are several approaches to tackling environmental issues.', 'Discussing solutions in an IELTS Part 3 discussion', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-approach-toeic', 'word-approach', 'toeic', 'In business English, "approach" means a method or strategy. Commonly used in TOEIC to discuss business strategies and management styles.', 'formal', 'The company has adopted a new approach to customer service.', 'Describing a business strategy in a TOEIC response', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-run-survival', 'word-run', 'survival', 'To run means to move quickly on foot. You might run to catch a bus or run when you are late.', 'neutral', 'I had to run to catch the bus.', 'Running to catch public transport', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-run-professional', 'word-run', 'professional', 'At work, "run" means to manage, operate, or lead something — like running a meeting or running a project.', 'neutral', 'She runs the marketing department.', 'Describing someone who leads a team', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-run-social', 'word-run', 'social', 'With friends, "run" has tons of casual uses — run errands, run into someone, or "I gotta run" meaning leaving.', 'informal', 'I gotta run — see you later!', 'Ending a casual hangout', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-handle-survival', 'word-handle', 'survival', 'To handle means to deal with or take care of something. You handle a problem, a situation, or a task.', 'neutral', 'Can you handle this? I need to step out.', 'Asking someone to take care of something', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-handle-professional', 'word-handle', 'professional', 'At work, "handle" means to manage or take responsibility for a situation, client, or project.', 'neutral', 'Let me handle the client call this afternoon.', 'Offering to take on a task at work', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-figure-survival', 'word-figure', 'survival', 'To figure out means to understand or solve something. You figure out directions, a problem, or how something works.', 'informal', 'I can''t figure out how to get there.', 'Trying to understand directions', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-figure-professional', 'word-figure', 'professional', 'At work, "figure" can mean to calculate or to understand data. A "figure" is also a number in a report.', 'neutral', 'The figures show an increase in revenue.', 'Reviewing a financial report', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-figure-social', 'word-figure', 'social', 'With friends, "figure out" is super common — it just means to understand or solve something casual.', 'informal', 'I figured out what to get her for her birthday!', 'Planning a surprise for a friend', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-spot-survival', 'word-spot', 'survival', 'A spot is a particular place or location. You find a spot to sit, a parking spot, or a meeting spot.', 'neutral', 'Is this spot taken?', 'Looking for a seat at a cafe', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-spot-professional', 'word-spot', 'professional', 'At work, "spot" can mean to notice or identify something, like spotting an error in a document.', 'neutral', 'Can you spot any issues in this report?', 'Reviewing a document with a colleague', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-spot-social', 'word-spot', 'social', 'With friends, "spot" is casual for a place or to notice something — "nice spot" or "spot on" (exactly right).', 'informal', 'This is a great spot for lunch!', 'Finding a good restaurant with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-turn-survival', 'word-turn', 'survival', 'To turn means to change direction. You turn left, turn right, or turn around when navigating.', 'neutral', 'Turn left at the next street.', 'Following directions to a new place', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-turn-professional', 'word-turn', 'professional', 'At work, "turn" often means to hand over or pass something along — like turning in a report or turning a project over.', 'neutral', 'Please turn in your report by Friday.', 'Setting a deadline at work', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-turn-social', 'word-turn', 'social', 'With friends, "your turn" is about taking turns in a game or activity.', 'informal', 'It''s your turn to pick the movie!', 'Deciding what to watch with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-book-survival', 'word-book', 'survival', 'To book means to reserve or arrange something in advance — a table, a ticket, an appointment.', 'neutral', 'I need to book a table for tonight.', 'Making a restaurant reservation', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-book-professional', 'word-book', 'professional', 'At work, "book" means to schedule a meeting or reserve resources like conference rooms.', 'neutral', 'Can you book the conference room for 2 PM?', 'Scheduling a meeting at the office', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-strike-survival', 'word-strike', 'survival', 'To strike means to hit. In news, a strike is when workers stop working to demand better conditions.', 'neutral', 'The bus workers are on strike this week.', 'Reading news about transit disruptions', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-strike-professional', 'word-strike', 'professional', 'At work, "strike" can refer to a labor action, or to remove something from a document.', 'formal', 'Please strike that paragraph from the contract.', 'Editing a formal document', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-point-survival', 'word-point', 'survival', 'A point is a specific idea or detail. "What is your point?" means "what are you trying to say?"', 'neutral', 'I don''t get the point of this form.', 'Filling out paperwork at an office', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-point-professional', 'word-point', 'professional', 'In meetings, "point" means a key idea or argument in a discussion.', 'formal', 'That is a very good point.', 'Agreeing with a colleague in a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-point-social', 'word-point', 'social', 'With friends, "point" is casual — "good point" (you are right) or "what is the point?" (why bother?).', 'informal', 'Good point — I didn''t think of that!', 'Chatting with friends about plans', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-charge-survival', 'word-charge', 'survival', 'To charge means to ask for payment. You get charged at a store, a restaurant, or for services.', 'neutral', 'Will they charge extra for delivery?', 'Asking about fees at a store', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-charge-professional', 'word-charge', 'professional', 'At work, "charge" can mean to take responsibility or to bill someone for services.', 'formal', 'She is in charge of the new project.', 'Assigning project leadership', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stand-survival', 'word-stand', 'survival', 'To stand means to be upright on your feet. You stand in line, stand at a counter, or stand on a bus.', 'neutral', 'We had to stand the whole way on the train.', 'Taking public transportation', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stand-professional', 'word-stand', 'professional', 'At work, "stand" means to hold a position or represent something — like "this stands for our values."', 'neutral', 'Our company stands for quality and trust.', 'Describing company values', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-stand-social', 'word-stand', 'social', 'With friends, "can not stand" means you really dislike something. "Stand" can also mean to tolerate.', 'informal', 'I can''t stand spicy food!', 'Discussing food preferences with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-pick-survival', 'word-pick', 'survival', 'To pick means to choose or select something. You pick a meal from a menu, pick a seat, or pick up an item.', 'neutral', 'You can pick any seat you like.', 'Choosing where to sit', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-pick-professional', 'word-pick', 'professional', 'At work, "pick" means to choose or select from options, often more casual than "select" or "choose."', 'neutral', 'Let''s pick the best option and move forward.', 'Deciding on a solution in a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-take-survival', 'word-take', 'survival', 'To take means to grab, accept, or use something. You take a bus, take a seat, take your time.', 'neutral', 'Take the next bus on Main Street.', 'Getting directions at a bus stop', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-take-professional', 'word-take', 'professional', 'At work, "take" is very common — take notes, take responsibility, take a meeting, take the lead.', 'neutral', 'Can you take notes during the meeting?', 'Asking a colleague to document a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-take-social', 'word-take', 'social', 'With friends, "take" is everywhere — take a break, take a photo, take it easy.', 'informal', 'Let''s take a selfie!', 'Hanging out and taking photos', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-take-ielts', 'word-take', 'ielts', 'In formal and academic English, "take" appears in phrases like "take into account," "take responsibility for," and "take measures." These structures demonstrate advanced vocabulary usage.', 'formal', 'We must take into account the various factors that contribute to this issue.', 'Discussing a complex topic in an IELTS Speaking test', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-take-toeic', 'word-take', 'toeic', 'In business English, "take" is used formally: "take action," "take measures," "take responsibility." These phrases are common in TOEIC contexts like meetings, reports, and emails.', 'formal', 'The company will take measures to address the issue promptly.', 'Discussing company policy in a TOEIC speaking task', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-followup-professional', 'word-follow-up', 'professional', 'In a professional context, "follow up" means to check back on something, send a reminder, or take the next step after a meeting or conversation. It shows initiative and reliability.', 'formal', 'I''d like to follow up on the email I sent yesterday.', 'Writing an email follow-up after a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-feedback-professional', 'word-feedback', 'professional', '"Feedback" means comments or evaluation about your work or performance. In professional settings, giving and receiving feedback is essential for growth.', 'formal', 'Could you provide feedback on the draft by Friday?', 'Requesting input on a document from a colleague', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-contribute-professional', 'word-contribute', 'professional', 'To contribute means to add value by sharing ideas, effort, or resources. In meetings, contributing means speaking up and sharing your perspective.', 'formal', 'I would like to contribute a few points to the discussion.', 'Speaking up in a team meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-network-professional', 'word-network', 'professional', 'To network means to build professional relationships by meeting and connecting with people in your field. Networking events, conferences, and LinkedIn are common ways to network.', 'formal', 'It''s important to network at industry events.', 'Attending a professional conference', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-summarize-professional', 'word-summarize', 'professional', 'To summarize means to give a brief statement of the main points. In professional settings, summarizing shows clarity and helps everyone stay aligned.', 'formal', 'Let me summarize the key takeaways from today.', 'Wrapping up a meeting', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-vibe-social', 'word-vibe', 'social', '"Vibe" is a super casual word for the feeling or atmosphere of a place or situation. You can say a place has good vibes, bad vibes, or a chill vibe.', 'informal', 'This place has such a good vibe!', 'Walking into a restaurant with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-crash-social', 'word-crash', 'social', 'With friends, "crash" means to show up somewhere uninvited or unplanned. You can crash a party, crash at someone''s place (stay over), or a game can crash (stop working).', 'informal', 'Can I crash at your place tonight?', 'Hanging out late with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-spoiler-social', 'word-spoiler', 'social', 'A "spoiler" is information that reveals what happens in a movie, show, or game. People say "no spoilers!" when they haven''t seen something yet.', 'informal', 'No spoilers! I haven''t seen the finale yet.', 'Talking about a TV show with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-trend-social', 'word-trend', 'social', 'A "trend" is something that is popular right now. Social media trends, fashion trends, or food trends — it''s what everyone is talking about or doing.', 'informal', 'Have you seen that trend on TikTok?', 'Discussing social media with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO word_mode_entries (id, word_id, mode_code, meaning_context, register, example_sentence, example_context, audio_id) VALUES ('wme-binge-social', 'word-binge', 'social', '"Binge" means to watch, play, or consume a lot of something all at once. Binge-watching a show means watching many episodes back-to-back.', 'informal', 'I binged the whole season last night!', 'Talking about a TV show with friends', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-cafe-survival', 'survival', 'survival', 'Ordering at a Cafe', 'You are at a cozy cafe. The barista greets you and asks what you would like to order.', ARRAY['word-brew','word-recommend','word-seasonal','word-fresh','word-order'], ARRAY['word-get','word-would-like'], '"Good morning! What can I get for you today? We have a fresh brew and some seasonal specials."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-cafe-professional', 'professional', 'professional', 'Coffee Meeting at the Office', 'You are at a coffee meeting with a colleague. Discuss project plans over coffee and practice professional language.', ARRAY['word-deadline','word-approach','word-handle','word-figure','word-point'], ARRAY['word-get','word-recommend'], '"Great to catch up! Shall we talk about the project while we grab our coffee?"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-cafe-social', 'social', 'social', 'Coffee with Friends', 'You are meeting friends at a cafe. Casual chat, jokes, and relaxed conversation.', ARRAY['word-stuff','word-carry','word-spot','word-turn','word-stand'], ARRAY['word-get','word-fresh'], '"Hey! Over here! Grab a seat — I already got us a table."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-doctor-survival', 'survival', 'survival', 'At the Doctor', 'You are at a doctor appointment. Practice explaining how you feel and understanding instructions.', ARRAY['word-appointment','word-charge','word-book','word-strike','word-pick'], ARRAY['word-take','word-run'], '"Hello, I am Dr. Kim. What brings you in today?"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-meeting-professional', 'professional', 'professional', 'Team Meeting at the Office', 'You are in a team meeting at work. Practice discussing project updates, giving opinions, and handling deadlines.', ARRAY['word-deadline','word-approach','word-handle','word-figure','word-point'], ARRAY['word-get','word-recommend'], '"Good morning, everyone. Let''s get started. I''d like to hear an update on the project."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-hanging-out-social', 'social', 'social', 'Hanging Out with Friends', 'You are chilling with friends at someone''s place. Casual conversation, jokes, and gaming talk.', ARRAY['word-stuff','word-carry','word-spot','word-turn','word-stand'], ARRAY['word-get','word-fresh'], '"Hey, come on in! We were just about to order some food. What are you in the mood for?"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-ielts-practice', 'ielts', 'ielts', 'IELTS Speaking Practice', 'Practice your IELTS Speaking test. Answer formal questions about familiar topics, then speak at length on a given topic.', ARRAY['word-approach','word-recommend','word-handle','word-point','word-figure'], ARRAY['word-get','word-take'], '"Good morning. My name is Alex, and I will be your examiner today. Let''s begin with Part 1. Can you tell me about what you do?"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-toeic-practice', 'toeic', 'toeic', 'TOEIC Speaking Practice', 'Practice your TOEIC Speaking test. Respond to questions about workplace situations and express your opinion clearly.', ARRAY['word-approach','word-recommend','word-handle','word-deadline','word-point'], ARRAY['word-get','word-take'], '"Hello. I would like to ask you a few questions about workplace scenarios. Please respond as clearly and completely as you can."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-email-followup-professional', 'professional', 'professional', 'Email Follow-up Conversation', 'You are following up on an email with a colleague. Practice professional language for checking in, clarifying points, and confirming next steps.', ARRAY['word-follow-up','word-feedback','word-contribute','word-summarize','word-point'], ARRAY['word-get','word-approach'], '"I got your email — thanks for sending that over. I had a few thoughts I wanted to share."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-performance-review-professional', 'professional', 'professional', 'Performance Review Discussion', 'You are in a performance review meeting with your manager. Practice discussing your achievements, receiving feedback, and setting goals.', ARRAY['word-feedback','word-handle','word-figure','word-charge','word-point'], ARRAY['word-get','word-recommend'], '"Thanks for coming in. I would like to go over your progress this quarter and discuss where we can support your growth."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-networking-conference-professional', 'professional', 'professional', 'Networking at a Conference', 'You are at a professional conference. Practice introducing yourself, exchanging ideas, and building connections with new colleagues.', ARRAY['word-network','word-approach','word-contribute','word-recommend','word-follow-up'], ARRAY['word-get','word-handle'], '"Hi there! I don''t think we''ve met — I''m Alex from the product team. What brings you to the conference?"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-gaming-social', 'social', 'social', 'Gaming Session Online', 'You are playing an online game with friends. Practice casual gaming language, callouts, and team coordination.', ARRAY['word-carry','word-crash','word-vibe','word-run','word-figure'], ARRAY['word-get','word-stuff'], '"Yo, you online? We''re starting a match in like two minutes — jump in!"', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-movie-night-social', 'social', 'social', 'Movie Night Discussion', 'You are discussing movies and shows with friends. Practice sharing opinions, recommending things, and reacting to spoilers.', ARRAY['word-binge','word-spoiler','word-recommend','word-spot','word-turn'], ARRAY['word-get','word-fresh'], '"Okay, what are we watching tonight? I vote for something I can binge."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenes (id, track_code, mode_code, title, description, target_word_ids, review_word_ids, dialogue_text, audio_url, created_at) VALUES ('scene-social-media-social', 'social', 'social', 'Social Media Trends', 'You are chatting with friends about what is trending online. Practice casual language for sharing, reacting, and discussing internet culture.', ARRAY['word-trend','word-vibe','word-stuff','word-stand','word-pick'], ARRAY['word-get','word-point'], '"Did you see that trend going around? It is everywhere right now."', NULL, now()) ON CONFLICT (id) DO NOTHING;
INSERT INTO conversation_scripts (scene_id, script_data) VALUES ('scene-cafe-survival', '[{"npcText":"Hi there! What can I get for you today?","branches":[{"matchPatterns":["would like","i''d like","order","get","have"],"npcText":"Great choice! We have a fresh brew today. Would you like to hear about our seasonal specials too?","hintLevel1":"Try: I would like...","hintLevel2":"Try saying: I''d like to order a coffee, please."},{"matchPatterns":["recommend","suggest","what do you"],"npcText":"Our fresh brew is really popular! And we have a seasonal blend with cinnamon and orange. Want to try one of those?","hintLevel1":"Try: Can you recommend...","hintLevel2":"Try saying: Can you recommend something good today?"}],"fallbackNpcText":"No worries! Our fresh brew is really popular. Would you like to try that?","hintLevel1":"Try: I would like...","hintLevel2":"Try saying: I''d like to get a coffee, please."},{"npcText":"So, would you like the fresh brew or something else?","branches":[{"matchPatterns":["fresh","brew","yes","sure"],"npcText":"One fresh brew coming up! You know, a lot of regulars order the seasonal blend too. It has a nice warm flavor. Want to add that?","hintLevel1":"Try: I will try the...","hintLevel2":"Try saying: I''ll try the fresh brew, please."},{"matchPatterns":["seasonal","special","cinnamon","orange","blend"],"npcText":"Nice! The seasonal blend has cinnamon and orange notes. It is really warming for this time of year. Shall I make that for you?","hintLevel1":"Try: I would like the...","hintLevel2":"Try saying: I would like the seasonal blend, please."}],"fallbackNpcText":"How about I recommend the fresh brew? It is one of our best sellers.","hintLevel1":"Try: The fresh brew sounds...","hintLevel2":"Try saying: The fresh brew sounds great."},{"npcText":"Since you mentioned you had a busy day, this is a nice spot to take a break. By the way, can I get you anything else? Maybe a pastry to go with that?","branches":[{"matchPatterns":["yes","sure","please","pastry","muffin","cake"],"npcText":"We have some fresh croissants today! I will add one to your order. Is there anything else you would like?","hintLevel1":"Try: Yes, I would...","hintLevel2":"Try saying: Yes, I would like a croissant, please."},{"matchPatterns":["no","that","fine","good","thanks","okay"],"npcText":"All right! Your order will be ready in just a moment. It was really nice talking with you!","hintLevel1":"Try: That sounds...","hintLevel2":"Try saying: That sounds good, thank you."}],"fallbackNpcText":"No problem at all! Your drink will be ready shortly. It was great chatting with you!","hintLevel1":"Try: No, that is...","hintLevel2":"Try saying: No, that is all. Thank you!"},{"npcText":"Here is your order! Enjoy your drink and have a wonderful rest of your day. Come back anytime!","branches":[],"fallbackNpcText":"","hintLevel1":"Try: Thank you...","hintLevel2":"Try saying: Thank you! Have a great day too."}]'::jsonb) ON CONFLICT (scene_id) DO NOTHING;
INSERT INTO conversation_scripts (scene_id, script_data) VALUES ('scene-cafe-professional', '[{"npcText":"Great to see you! Before we dive in, how has your week been? Anything exciting happening?","branches":[{"matchPatterns":["busy","project","deadline","meeting","work"],"npcText":"I hear you. We have a deadline coming up on our end too. Speaking of which — did you get a chance to review the approach document I sent?","hintLevel1":"Try: It has been busy...","hintLevel2":"Try saying: It has been busy with the project deadline."},{"matchPatterns":["good","great","fine","okay","well"],"npcText":"Glad to hear it! So, I wanted to handle a few things today. First — did you get my email about the deadline change?","hintLevel1":"Try: It was good...","hintLevel2":"Try saying: It was good! Ready to discuss the project."}],"fallbackNpcText":"No worries if you do not want to get into it! So, let me run you through the key points from the project update.","hintLevel1":"Try: It was...","hintLevel2":"Try saying: It was pretty good, thanks!","reviewWordHint":"You learned ''get'' meaning ''to order'' — here it means ''to understand or receive''!"},{"npcText":"So what do you think about the new approach? I figure we could handle the client side differently this time.","branches":[{"matchPatterns":["agree","think","approach","point","handle","yes"],"npcText":"Good point! I think we can handle this more efficiently. Let me take the lead on the client presentation — would that work?","hintLevel1":"Try: I think the approach...","hintLevel2":"Try saying: I think the new approach makes a good point about efficiency."},{"matchPatterns":["deadline","time","rush","concern","worried"],"npcText":"Fair enough — the deadline is tight. But I figure if we handle it in phases, we can make it work. What do you think?","hintLevel1":"Try: The deadline is...","hintLevel2":"Try saying: The deadline is a concern, but the approach could work."}],"fallbackNpcText":"No worries if you need time to think it over. The main point is that we have a new deadline to meet.","hintLevel1":"Try: I think...","hintLevel2":"Try saying: I think we should approach this differently."},{"npcText":"One last thing — can you take the lead on the follow-up report? The figures need to be ready by Thursday.","branches":[{"matchPatterns":["yes","sure","take","handle","will","can"],"npcText":"Excellent. I will get back to you with the latest figures by tomorrow. Great working with you on this!","hintLevel1":"Try: Yes, I can...","hintLevel2":"Try saying: Yes, I can handle the follow-up report."},{"matchPatterns":["not sure","busy","need help","maybe"],"npcText":"No problem — I can take point on some of it. We will figure it out together.","hintLevel1":"Try: I am not sure I can...","hintLevel2":"Try saying: I might need some help with the deadline."}],"fallbackNpcText":"Take your time. If you need any figures or help, just let me know. We can handle this!","hintLevel1":"Try: I can...","hintLevel2":"Try saying: I can take care of the report by Thursday."},{"npcText":"That was a productive meeting. Thanks for your time — I will send you the action items shortly.","branches":[],"fallbackNpcText":"","hintLevel1":"Try: Thank you...","hintLevel2":"Try saying: Thanks! I will get back to you on those items."}]'::jsonb) ON CONFLICT (scene_id) DO NOTHING;
INSERT INTO conversation_scripts (scene_id, script_data) VALUES ('scene-cafe-social', '[{"npcText":"Hey, come on in! We were just about to order some food. What are you in the mood for?","branches":[{"matchPatterns":["pizza","burger","chinese","thai","mexican","sushi","food","eat","order","stuff"],"npcText":"Nice, that sounds dope! Yeah, let''s get some stuff ordered. You grab a spot on the couch — this place is a great spot to chill.","hintLevel1":"Try: I feel like...","hintLevel2":"Try saying: I''m down for pizza. Let''s order!"},{"matchPatterns":["not sure","whatever","anything","you pick","don care","no cap"],"npcText":"No worries, I''ll just order the usual — pizza and wings. You cool with that? By the way, nice spot on the couch!","hintLevel1":"Try: Whatever you...","hintLevel2":"Try saying: Whatever you want is cool with me."}],"fallbackNpcText":"No stress! I''ll just order a bunch of stuff. We always get too much anyway. Grab a seat — this is a great spot!","hintLevel1":"Try: I am in the mood for...","hintLevel2":"Try saying: I''m in the mood for pizza, I guess.","reviewWordHint":"You learned ''get'' meaning ''to order'' — here it means ''to understand or have''!"},{"npcText":"So did you carry the team last night in the game? I heard you were absolutely carrying!","branches":[{"matchPatterns":["carry","carried","won","win","game","play","play"],"npcText":"No cap, that was a wild game! I turned in early though — couldn''t stand staying up another round. Anyway, want to run a quick game while we wait for food?","hintLevel1":"Try: Yeah, I carried...","hintLevel2":"Try saying: Yeah, I carried the team last night!"},{"matchPatterns":["no","did not","lost","terrible","bad","rough"],"npcText":"Aw, that''s rough! No worries though, every game can''t be a carry. Next time you''ll turn it around. Hey, want to run a quick game while we wait for food?","hintLevel1":"Try: No, it was...","hintLevel2":"Try saying: Nah, I didn''t do great. But it was still fun!"}],"fallbackNpcText":"All good! Hey, want to run a quick game while we wait for the food? I figure we got time for a couple rounds.","hintLevel1":"Try: Yeah, it was...","hintLevel2":"Try saying: Yeah, it was pretty fun!"},{"npcText":"Hey, can you figure out how to connect the controller? I can''t stand when this stuff doesn''t work.","branches":[{"matchPatterns":["figure","figure out","try","sure","turn","button","connect"],"npcText":"Awesome, thanks! While you do that, I''ll grab the snacks. This is exactly the kind of stuff that makes hanging out fun, right?","hintLevel1":"Try: I can figure out...","hintLevel2":"Try saying: Let me figure out how to connect it."},{"matchPatterns":["no","can not","not sure","try","different"],"npcText":"No worries, we can just use the phone instead. I can''t stand when tech doesn''t cooperate! Let me grab the snacks at least.","hintLevel1":"Try: I am not sure...","hintLevel2":"Try saying: I''m not sure I can figure it out, but let me try."}],"fallbackNpcText":"All good, we''ll figure it out! Let me grab the snacks real quick.","hintLevel1":"Try: Let me try...","hintLevel2":"Try saying: Let me try to figure it out."},{"npcText":"That was a great time! We should do this more often. Same spot next week?","branches":[],"fallbackNpcText":"","hintLevel1":"Try: Yeah, sounds...","hintLevel2":"Try saying: Yeah, that was fun! Same spot next week for sure."}]'::jsonb) ON CONFLICT (scene_id) DO NOTHING;
INSERT INTO conversation_scripts (scene_id, script_data) VALUES ('scene-doctor-survival', '[{"npcText":"Hi there! What can I get for you today?","branches":[{"matchPatterns":["would like","i''d like","order","get","have"],"npcText":"Great choice! We have a fresh brew today. Would you like to hear about our seasonal specials too?","hintLevel1":"Try: I would like...","hintLevel2":"Try saying: I''d like to order a coffee, please."},{"matchPatterns":["recommend","suggest","what do you"],"npcText":"Our fresh brew is really popular! And we have a seasonal blend with cinnamon and orange. Want to try one of those?","hintLevel1":"Try: Can you recommend...","hintLevel2":"Try saying: Can you recommend something good today?"}],"fallbackNpcText":"No worries! Our fresh brew is really popular. Would you like to try that?","hintLevel1":"Try: I would like...","hintLevel2":"Try saying: I''d like to get a coffee, please."},{"npcText":"So, would you like the fresh brew or something else?","branches":[{"matchPatterns":["fresh","brew","yes","sure"],"npcText":"One fresh brew coming up! You know, a lot of regulars order the seasonal blend too. It has a nice warm flavor. Want to add that?","hintLevel1":"Try: I will try the...","hintLevel2":"Try saying: I''ll try the fresh brew, please."},{"matchPatterns":["seasonal","special","cinnamon","orange","blend"],"npcText":"Nice! The seasonal blend has cinnamon and orange notes. It is really warming for this time of year. Shall I make that for you?","hintLevel1":"Try: I would like the...","hintLevel2":"Try saying: I would like the seasonal blend, please."}],"fallbackNpcText":"How about I recommend the fresh brew? It is one of our best sellers.","hintLevel1":"Try: The fresh brew sounds...","hintLevel2":"Try saying: The fresh brew sounds great."},{"npcText":"Since you mentioned you had a busy day, this is a nice spot to take a break. By the way, can I get you anything else? Maybe a pastry to go with that?","branches":[{"matchPatterns":["yes","sure","please","pastry","muffin","cake"],"npcText":"We have some fresh croissants today! I will add one to your order. Is there anything else you would like?","hintLevel1":"Try: Yes, I would...","hintLevel2":"Try saying: Yes, I would like a croissant, please."},{"matchPatterns":["no","that","fine","good","thanks","okay"],"npcText":"All right! Your order will be ready in just a moment. It was really nice talking with you!","hintLevel1":"Try: That sounds...","hintLevel2":"Try saying: That sounds good, thank you."}],"fallbackNpcText":"No problem at all! Your drink will be ready shortly. It was great chatting with you!","hintLevel1":"Try: No, that is...","hintLevel2":"Try saying: No, that is all. Thank you!"},{"npcText":"Here is your order! Enjoy your drink and have a wonderful rest of your day. Come back anytime!","branches":[],"fallbackNpcText":"","hintLevel1":"Try: Thank you...","hintLevel2":"Try saying: Thank you! Have a great day too."}]'::jsonb) ON CONFLICT (scene_id) DO NOTHING;
INSERT INTO conversation_scripts (scene_id, script_data) VALUES ('scene-meeting-professional', '[{"npcText":"Great to see you! Before we dive in, how has your week been? Anything exciting happening?","branches":[{"matchPatterns":["busy","project","deadline","meeting","work"],"npcText":"I hear you. We have a deadline coming up on our end too. Speaking of which — did you get a chance to review the approach document I sent?","hintLevel1":"Try: It has been busy...","hintLevel2":"Try saying: It has been busy with the project deadline."},{"matchPatterns":["good","great","fine","okay","well"],"npcText":"Glad to hear it! So, I wanted to handle a few things today. First — did you get my email about the deadline change?","hintLevel1":"Try: It was good...","hintLevel2":"Try saying: It was good! Ready to discuss the project."}],"fallbackNpcText":"No worries if you do not want to get into it! So, let me run you through the key points from the project update.","hintLevel1":"Try: It was...","hintLevel2":"Try saying: It was pretty good, thanks!","reviewWordHint":"You learned ''get'' meaning ''to order'' — here it means ''to understand or receive''!"},{"npcText":"So what do you think about the new approach? I figure we could handle the client side differently this time.","branches":[{"matchPatterns":["agree","think","approach","point","handle","yes"],"npcText":"Good point! I think we can handle this more efficiently. Let me take the lead on the client presentation — would that work?","hintLevel1":"Try: I think the approach...","hintLevel2":"Try saying: I think the new approach makes a good point about efficiency."},{"matchPatterns":["deadline","time","rush","concern","worried"],"npcText":"Fair enough — the deadline is tight. But I figure if we handle it in phases, we can make it work. What do you think?","hintLevel1":"Try: The deadline is...","hintLevel2":"Try saying: The deadline is a concern, but the approach could work."}],"fallbackNpcText":"No worries if you need time to think it over. The main point is that we have a new deadline to meet.","hintLevel1":"Try: I think...","hintLevel2":"Try saying: I think we should approach this differently."},{"npcText":"One last thing — can you take the lead on the follow-up report? The figures need to be ready by Thursday.","branches":[{"matchPatterns":["yes","sure","take","handle","will","can"],"npcText":"Excellent. I will get back to you with the latest figures by tomorrow. Great working with you on this!","hintLevel1":"Try: Yes, I can...","hintLevel2":"Try saying: Yes, I can handle the follow-up report."},{"matchPatterns":["not sure","busy","need help","maybe"],"npcText":"No problem — I can take point on some of it. We will figure it out together.","hintLevel1":"Try: I am not sure I can...","hintLevel2":"Try saying: I might need some help with the deadline."}],"fallbackNpcText":"Take your time. If you need any figures or help, just let me know. We can handle this!","hintLevel1":"Try: I can...","hintLevel2":"Try saying: I can take care of the report by Thursday."},{"npcText":"That was a productive meeting. Thanks for your time — I will send you the action items shortly.","branches":[],"fallbackNpcText":"","hintLevel1":"Try: Thank you...","hintLevel2":"Try saying: Thanks! I will get back to you on those items."}]'::jsonb) ON CONFLICT (scene_id) DO NOTHING;
